const cityAliases = {
  'алматы': 'Алматы',
  'астана': 'Астана',
  'нур-султан': 'Астана',
  'нурсултан': 'Астана',
  'шымкент': 'Шымкент',
  'караганда': 'Караганда',
  'актау': 'Актау',
  'атырау': 'Атырау',
  'павлодар': 'Павлодар',
  'костанай': 'Костанай',
  'усть-каменогорск': 'Усть-Каменогорск',
};

const knownActivities = [
  'Строительство зданий и сооружений',
  'Консалтинговые услуги',
  'Образовательные услуги',
  'Телекоммуникации',
  'Розничная торговля',
  'Техническое обслуживание оборудования',
  'Производство продуктов питания',
  'Сельское хозяйство',
  'Добыча полезных ископаемых',
  'Транспорт и логистика',
  'Медицинские услуги',
  'Архитектура и проектирование',
  'Оптовая торговля',
  'Рекламные услуги',
  'Разработка программного обеспечения',
  'Юридические услуги',
  'Производство мебели',
  'Финансовые услуги',
  'Бухгалтерский учёт и аудит',
  'Ресторанный бизнес',
];

function detectCity(lower) {
  const cityRules = [
    { canon: 'Астана', regex: /(нур-?султан|астан)/i },
    { canon: 'Алматы', regex: /(алмат)/i },
    { canon: 'Шымкент', regex: /(шымкент)/i },
    { canon: 'Караганда', regex: /(караганд)/i },
    { canon: 'Актау', regex: /(актау)/i },
    { canon: 'Атырау', regex: /(атырау)/i },
    { canon: 'Павлодар', regex: /(павлодар)/i },
    { canon: 'Костанай', regex: /(костанай)/i },
    { canon: 'Усть-Каменогорск', regex: /(усть-?каменогорск)/i },
  ];

  for (const rule of cityRules) {
    if (rule.regex.test(lower)) return rule.canon;
  }

  for (const [alias, canon] of Object.entries(cityAliases)) {
    if (lower.includes(alias)) return canon;
  }

  return null;
}

function detectActivity(chatInput, lower) {
  // 1) Exact activity phrase from dataset
  for (const v of knownActivities) {
    if (lower.includes(v.toLowerCase())) return v;
  }

  // 2) Heuristic mapping for common intents
  if (/(разработк|программ|it|айти|software|технолог)/i.test(lower)) {
    return 'Разработка программного обеспечения';
  }
  if (/(строит|construction|зданий|сооружений)/i.test(lower)) {
    return 'Строительство зданий и сооружений';
  }
  if (/(технич|обслуживан.*оборуд)/i.test(lower)) {
    return 'Техническое обслуживание оборудования';
  }
  if (/(архитект|проектирован)/i.test(lower)) {
    return 'Архитектура и проектирование';
  }
  if (/(транспорт|логист|доставк|склад)/i.test(lower)) {
    return 'Транспорт и логистика';
  }
  if (/(оптов)/i.test(lower)) {
    return 'Оптовая торговля';
  }
  if (/(рознич)/i.test(lower)) {
    return 'Розничная торговля';
  }
  if (/(финанс|банк|инвест|страх)/i.test(lower)) {
    return 'Финансовые услуги';
  }

  return null;
}

function detectCompanyName(chatInput) {
  const m = chatInput.match(/(?:ТОО|АО|ИП)\s+"[^"]+"/i);
  if (m && m[0]) {
    // normalize legal form upper-case and spacing
    return m[0]
      .replace(/^тоо/i, 'ТОО')
      .replace(/^ао/i, 'АО')
      .replace(/^ип/i, 'ИП')
      .replace(/\s+/g, ' ')
      .trim();
  }
  return null;
}

return $input.all().map((item) => {
  const original = item.json || {};
  const chatInput = String(original.chatInput ?? '').trim();
  const lower = chatInput.toLowerCase();

  const city = detectCity(lower);
  const activity = detectActivity(chatInput, lower);
  const companyName = detectCompanyName(chatInput);

  const binMatch = chatInput.match(/\b\d{12}\b/);
  const bin = binMatch ? binMatch[0] : null;

  let status = null;
  if (lower.includes('неактив') || lower.includes('ликвид') || lower.includes('закрыт') || lower.includes('приостанов')) {
    status = 'Ликвидировано';
  } else if (lower.includes('активн')) {
    status = 'Активно';
  }

  const isCount = /(сколько|количество|число)/i.test(lower);
  const isStatusLookup = /(какой\s+статус|статус\s+у\s+компани)/i.test(lower);
  const isDateLookup = /(дата\s+регистрац|когда\s+зарегистр)/i.test(lower);
  const isActivityLookup = /(вид\s+деятельност)/i.test(lower);
  const isList = /(найди|покажи|перечисли|какие|список|все|подбери)/i.test(lower);

  // Hard anti-hallucination guard: detect unsupported asks for fields absent in dataset.
  const asksUnsupportedField = /(выручк|доход|оборот|прибыл|маржин|ebitda|дивиденд|капитализац|активы|баланс|телефон|e-?mail|почт|сайт|адрес|руководител|учредител|директор|владелец|штат|сотрудник)/i.test(lower);
  const asksRankingWithoutMetric = /(крупнейш|топ\s*\d+|лучши|сам(ый|ая|ое|ые))/i.test(lower);

  let unsupportedReason = null;
  if (asksUnsupportedField) {
    unsupportedReason = 'Запрошены поля, которых нет в источнике данных.';
  } else if (asksRankingWithoutMetric) {
    unsupportedReason = 'Запрошен рейтинг/сравнение, но в источнике нет метрик ранжирования.';
  }

  let queryMode = 'generic';
  if (unsupportedReason) queryMode = 'unsupported';
  else if (isCount) queryMode = 'count';
  else if (bin) queryMode = 'bin_lookup';
  else if (isStatusLookup) queryMode = 'status_lookup';
  else if (isDateLookup) queryMode = 'registration_date_lookup';
  else if (isActivityLookup) queryMode = 'activity_lookup';
  else if (isList) queryMode = 'list';

  let topK = 10;
  if (queryMode === 'unsupported') topK = 1;
  else if (queryMode === 'bin_lookup') topK = 1;
  else if (queryMode === 'count') topK = 200;
  else if (queryMode === 'list') topK = 50;

  const must = [];
  if (bin) must.push({ key: 'metadata.bin', match: { value: bin } });
  if (companyName) must.push({ key: 'metadata.name', match: { value: companyName } });
  if (city) must.push({ key: 'metadata.city', match: { value: city } });
  if (status) must.push({ key: 'metadata.status', match: { value: status } });
  if (activity) must.push({ key: 'metadata.activity', match: { value: activity } });

  const qdrantFilter = must.length ? { must } : {};

  const filterParts = [];
  if (bin) filterParts.push(`бин=${bin}`);
  if (companyName) filterParts.push(`название=${companyName}`);
  if (city) filterParts.push(`город=${city}`);
  if (status) filterParts.push(`статус=${status}`);
  if (activity) filterParts.push(`вид_деятельности=${activity}`);

  const retrievalHint = [
    `query_mode=${queryMode}`,
    unsupportedReason ? `unsupported_reason=${unsupportedReason}` : '',
    'Используй только факты из контекста.',
    'Если подходящих записей нет, верни недостаточно данных.',
  ].filter(Boolean).join('\n');

  const retrievalQuery = [
    retrievalHint,
    chatInput,
    filterParts.length ? `Фильтры: ${filterParts.join(', ')}` : '',
  ].filter(Boolean).join('\n');

  return {
    json: {
      ...original,
      chatInput,
      queryMode,
      topK,
      unsupportedReason,
      parsedFilters: {
        bin,
        companyName,
        city,
        status,
        activity,
      },
      qdrantFilter,
      retrievalQuery,
    },
  };
});

const items = $input.all();

function compact(s) {
  return String(s || '').replace(/\s+/g, ' ').trim();
}

function pickQueryItem(allItems) {
  // Prefer the original strategy item, not document items from Qdrant load.
  return allItems.find((i) => {
    const j = i?.json || {};
    return Boolean(j.queryMode || j.qdrantFilter || j.parsedFilters || j.topK || j.unsupportedReason);
  }) || { json: {} };
}

const queryItem = pickQueryItem(items);
const query = queryItem.json || {};
const filters = (query.parsedFilters && typeof query.parsedFilters === 'object') ? query.parsedFilters : {};
const queryMode = compact(query.queryMode || 'generic');
const unsupportedReason = compact(query.unsupportedReason || '');

if (queryMode === 'unsupported' || unsupportedReason) {
  return [{
    json: {
      response: {
        text: 'Недостаточно данных в контексте. Доступны только поля: БИН, название, город, статус, вид деятельности, дата регистрации.',
      },
    },
  }];
}

const docs = items
  .filter((i) => i?.json?.document)
  .map((i) => i.json.document)
  .filter(Boolean);

function normalizeRecord(doc) {
  const m = doc?.metadata || {};
  const rec = {
    bin: compact(m.bin),
    name: compact(m.name),
    city: compact(m.city),
    status: compact(m.status),
    activity: compact(m.activity),
    registration_date: compact(m.registration_date),
  };
  if (!/^\d{12}$/.test(rec.bin)) return null;
  return rec;
}

let records = docs.map(normalizeRecord).filter(Boolean);

// Deduplicate by BIN to avoid repeated evidence lines.
const uniqMap = new Map();
for (const r of records) {
  if (!uniqMap.has(r.bin)) uniqMap.set(r.bin, r);
}
records = [...uniqMap.values()];

function matchesFilters(r) {
  if (filters.bin && r.bin !== String(filters.bin)) return false;
  if (filters.companyName && r.name !== String(filters.companyName)) return false;
  if (filters.city && r.city !== String(filters.city)) return false;
  if (filters.status && r.status !== String(filters.status)) return false;
  if (filters.activity && r.activity !== String(filters.activity)) return false;
  return true;
}

const filtered = records.filter(matchesFilters);

if (!filtered.length) {
  return [{ json: { response: { text: 'Недостаточно данных в контексте.' } } }];
}

let answer = '';
if (queryMode === 'count') {
  answer = String(filtered.length);
} else if (queryMode === 'status_lookup') {
  answer = filtered[0].status || 'Недостаточно данных в контексте.';
} else if (queryMode === 'registration_date_lookup') {
  answer = filtered[0].registration_date || 'Недостаточно данных в контексте.';
} else if (queryMode === 'activity_lookup') {
  answer = filtered[0].activity || 'Недостаточно данных в контексте.';
} else if (queryMode === 'bin_lookup') {
  const r = filtered[0];
  answer = `${r.name}, ${r.city}, ${r.status}`;
} else {
  const names = [...new Set(filtered.map((r) => r.name).filter(Boolean))].slice(0, 5);
  answer = names.length ? names.join(', ') : 'Недостаточно данных в контексте.';
}

const evidenceLines = filtered.slice(0, 3).map((r) => {
  return `Название: ${r.name} | БИН: ${r.bin} | Город: ${r.city} | Статус: ${r.status}`;
});

let finalText = answer;
if (evidenceLines.length) {
  finalText += '\n\nПодтверждение:\n' + evidenceLines.map((x) => `- ${x}`).join('\n');
}

return [{ json: { response: { text: finalText } } }];
